import React, { useCallback, useEffect, useState } from 'react';
import { Pressable, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import CustomerBottomNav from '../components/CustomerBottomNav';
import { useFocusEffect } from '@react-navigation/native';
import { createShadow } from '../styles/shadows';

const CustomerSubscriptionScreen = () => {
  const [showForm, setShowForm] = useState(false);
  const [qty, setQty] = useState(0);
  const [qtyText, setQtyText] = useState('0');
  const [frequency, setFrequency] = useState<'Daily' | 'Weekly' | 'Monthly'>('Daily');
  const [time, setTime] = useState<'Morning' | 'Afternoon' | 'Evening'>('Morning');
  const [activeSubscription, setActiveSubscription] = useState<{
    qty: number;
    frequency: 'Daily' | 'Weekly' | 'Monthly';
    time: 'Morning' | 'Afternoon' | 'Evening';
  } | null>(null);
  const [loaded, setLoaded] = useState(false);
  const storageKey = 'customerSubscription';

  const loadSubscription = useCallback(async () => {
    try {
      const saved = await AsyncStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed?.qty && parsed?.frequency && parsed?.time) {
          setActiveSubscription(parsed);
        } else {
          setActiveSubscription(null);
        }
      } else {
        setActiveSubscription(null);
      }
    } catch {
      setActiveSubscription(null);
    } finally {
      setLoaded(true);
    }
  }, []);

  useEffect(() => {
    loadSubscription();
  }, [loadSubscription]);

  useFocusEffect(
    useCallback(() => {
      loadSubscription();
    }, [loadSubscription])
  );
  const handleSave = async () => {
    const payload = { qty, frequency, time };
    await AsyncStorage.setItem(storageKey, JSON.stringify(payload));
    setActiveSubscription(payload);
    setShowForm(false);
  };

  const syncQty = (value: number) => {
    const next = Math.max(0, value);
    setQty(next);
    setQtyText(String(next));
  };

  const handleQtyChange = (value: string) => {
    const digitsOnly = value.replace(/[^0-9]/g, '');
    setQtyText(digitsOnly);
    if (!digitsOnly) {
      return;
    }
    const parsed = parseInt(digitsOnly, 10);
    if (Number.isFinite(parsed)) {
      setQty(Math.max(0, parsed));
    }
  };

  const handleQtyBlur = () => {
    if (!qtyText.trim()) {
      syncQty(0);
      return;
    }
    const parsed = parseInt(qtyText, 10);
    if (!Number.isFinite(parsed) || parsed < 0) {
      syncQty(0);
      return;
    }
    syncQty(parsed);
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.title}>Subscription</Text>
        <Text style={styles.subtitle}>Manage your recurring orders here.</Text>

        {loaded && !activeSubscription && !showForm ? (
          <View style={styles.emptyState}>
            <Text style={styles.emptyIcon}>📦</Text>
            <Text style={styles.emptyText}>No subscription yet</Text>
            <Text style={styles.emptySubtext}>Create a plan to get water delivered automatically.</Text>
            <Pressable style={styles.emptyButton} onPress={() => setShowForm(true)}>
              <Text style={styles.emptyButtonText}>Create subscription</Text>
            </Pressable>
          </View>
        ) : null}

        {showForm ? (
          <View style={styles.formCard}>
            <Text style={styles.formTitle}>Create subscription</Text>

            <Text style={styles.formLabel}>Quantity</Text>
            <View style={styles.qtyRow}>
              <TextInput
                style={styles.qtyInput}
                value={qtyText}
                onChangeText={handleQtyChange}
                onBlur={handleQtyBlur}
                keyboardType="number-pad"
                returnKeyType="done"
                textAlign="center"
                selectTextOnFocus
                maxLength={3}
                placeholder="0"
                placeholderTextColor="#94A3B8"
              />
              <Text style={styles.qtyHint}>Type the exact number of cans</Text>
            </View>

            <Text style={styles.formLabel}>Delivery frequency</Text>
            <View style={styles.optionRow}>
              {(['Daily', 'Weekly', 'Monthly'] as const).map((option) => (
                <Pressable
                  key={option}
                  style={[styles.optionChip, frequency === option && styles.optionChipActive]}
                  onPress={() => setFrequency(option)}
                >
                  <Text style={[styles.optionText, frequency === option && styles.optionTextActive]}>{option}</Text>
                </Pressable>
              ))}
            </View>

            <Text style={styles.formLabel}>Preferred time</Text>
            <View style={styles.optionRow}>
              {(['Morning', 'Afternoon', 'Evening'] as const).map((option) => (
                <Pressable
                  key={option}
                  style={[styles.optionChip, time === option && styles.optionChipActive]}
                  onPress={() => setTime(option)}
                >
                  <Text style={[styles.optionText, time === option && styles.optionTextActive]}>{option}</Text>
                </Pressable>
              ))}
            </View>

            <Pressable style={styles.saveButton} onPress={handleSave}>
              <Text style={styles.saveButtonText}>Save subscription</Text>
            </Pressable>
          </View>
        ) : null}

        {activeSubscription && !showForm ? (
          <View style={styles.activeCard}>
            <Text style={styles.activeTitle}>Active subscription</Text>
            <Text style={styles.activeRow}>Quantity: {activeSubscription.qty} cans</Text>
            <Text style={styles.activeRow}>Frequency: {activeSubscription.frequency}</Text>
            <Text style={styles.activeRow}>Time: {activeSubscription.time}</Text>
            <Pressable style={styles.editButton} onPress={() => setShowForm(true)}>
              <Text style={styles.editButtonText}>Edit subscription</Text>
            </Pressable>
          </View>
        ) : null}
      </View>
      <CustomerBottomNav active="CustomerSubscription" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F6FB',
    position: 'relative',
    height: '100%'
  },
  content: {
    padding: 18,
    paddingBottom: 90
  },
  title: {
    fontSize: 22,
    fontWeight: '800',
    color: '#0F172A',
    marginBottom: 6
  },
  subtitle: {
    color: '#64748B'
  },
  emptyState: {
    flex: 1,
    marginTop: 30,
    alignItems: 'center',
    justifyContent: 'center'
  },
  emptyIcon: {
    fontSize: 40,
    marginBottom: 10
  },
  emptyText: {
    color: '#DC2626',
    fontWeight: '800',
    fontSize: 16
  },
  emptySubtext: {
    marginTop: 6,
    color: '#94A3B8',
    textAlign: 'center',
    maxWidth: 240
  },
  emptyButton: {
    marginTop: 14,
    backgroundColor: '#0B61A4',
    borderRadius: 12,
    paddingVertical: 10,
    paddingHorizontal: 20,
    ...createShadow({ color: '#0B61A4', opacity: 0.2, radius: 10, elevation: 4 })
  },
  emptyButtonText: {
    color: 'white',
    fontWeight: '800'
  },
  formCard: {
    marginTop: 20,
    backgroundColor: 'white',
    borderRadius: 16,
    padding: 16,
    ...createShadow({ color: '#000', opacity: 0.05, radius: 12, elevation: 4 })
  },
  formTitle: {
    fontSize: 16,
    fontWeight: '800',
    color: '#0F172A',
    marginBottom: 12
  },
  formLabel: {
    fontSize: 12,
    fontWeight: '700',
    color: '#64748B',
    marginTop: 10,
    marginBottom: 6
  },
  qtyRow: {
    gap: 8
  },
  qtyInput: {
    backgroundColor: '#F8FBFF',
    borderRadius: 16,
    borderWidth: 1,
    borderColor: '#B9DFF3',
    paddingVertical: 14,
    paddingHorizontal: 12,
    fontSize: 22,
    fontWeight: '900',
    color: '#0F172A'
  },
  qtyHint: {
    color: '#5C7890',
    fontSize: 12,
    marginTop: 2
  },
  optionRow: {
    flexDirection: 'row',
    gap: 10,
    flexWrap: 'wrap'
  },
  optionChip: {
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderRadius: 999,
    backgroundColor: '#F1F5F9'
  },
  optionChipActive: {
    backgroundColor: '#0B61A4'
  },
  optionText: {
    fontSize: 12,
    fontWeight: '700',
    color: '#64748B'
  },
  optionTextActive: {
    color: 'white'
  },
  saveButton: {
    marginTop: 16,
    backgroundColor: '#0B61A4',
    borderRadius: 12,
    paddingVertical: 12,
    alignItems: 'center',
    ...createShadow({ color: '#0B61A4', opacity: 0.2, radius: 10, elevation: 4 })
  },
  saveButtonText: {
    color: 'white',
    fontWeight: '800'
  },
  activeCard: {
    marginTop: 24,
    backgroundColor: 'white',
    borderRadius: 18,
    padding: 20,
    width: '100%',
    alignSelf: 'center',
    ...createShadow({ color: '#000', opacity: 0.05, radius: 12, elevation: 4 })
  },
  activeTitle: {
    fontSize: 18,
    fontWeight: '800',
    color: '#0F172A',
    marginBottom: 12
  },
  activeRow: {
    fontSize: 14,
    fontWeight: '700',
    color: '#475569',
    marginBottom: 8
  },
  editButton: {
    marginTop: 16,
    alignSelf: 'flex-start',
    backgroundColor: '#E2E8F0',
    paddingVertical: 8,
    paddingHorizontal: 14,
    borderRadius: 12
  },
  editButtonText: {
    fontSize: 13,
    fontWeight: '700',
    color: '#0B61A4'
  }
});

export default CustomerSubscriptionScreen;
